class RoleSelectionScreen extends StatelessWidget{ const RoleSelectionScreen({super.key}); @override Widget build(BuildContext context){ return Scaffold(appBar: AppBar(title: Text('Aap Kaun Hain?')), body: Padding(padding: EdgeInsets.all(16), child: Column(children: [SizedBox(height: 20), Text('Select Account Type', style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)), SizedBox(height: 20), _card(context, 'Customer Hoon', 'Kaam karwana hai', Icons.person, Colors.blue[50]!, UserRole.customer), SizedBox(height: 16), _card(context, 'Mahir Hoon', 'Kaam karna hai', Icons.build, Colors.orange[50]!, UserRole.provider)]))); } Widget _card(BuildContext context, String t, String s, IconData ic, Color c, UserRole r){ return GestureDetector(onTap: (){ AuthProvider.setRole(r); Navigator.push(context, MaterialPageRoute(builder: (_)=> MainNavigationScreen(role: r))); }, child: Container(padding: EdgeInsets.all(20), decoration: BoxDecoration(color: c, borderRadius: BorderRadius.circular(16)), child: Row(children: [CircleAvatar(backgroundColor: Colors.white, radius: 30, child: Icon(ic, size: 30)), SizedBox(width: 16), Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [Text(t, style: TextStyle(fontWeight: FontWeight.bold)), Text(s, style: TextStyle(color: Colors.grey[600]))]))]))); } }
